critical_note.correct_pattern:

/* Widget Styles - Carbon Design System */
/* Colors and typography aligned with themes/Carbon.less */

.widget_maincontentbox {
    font-family: 'IBM Plex Sans', 'Helvetica Neue', Helvetica, Arial, sans-serif; /* @bpm-font-family-sans-serif */
    font-size: 14px; /* @bpm-font-size-base */
    color: #161616; /* @bpm-text-color */
}

.widget-primary {
    background-color: #0f62fe; /* @bpm-color-primary */
    border-color: #e0e0e0; /* Gray 20 */
}

.widget-text {
    font-size: 12px; /* @bpm-font-size-small */
    color: #525252; /* Gray 70 */
}

critical_note.wrong_pattern:

/* WRONG: Do NOT use LESS variables - they won't work in InlineCSS.css */
.widget_maincontentbox {
    font-family: @bpm-font-family-sans-serif;  /* ❌ Will not compile */
    font-size: @bpm-font-size-base;            /* ❌ Will not compile */
    color: @bpm-text-color;                    /* ❌ Will not compile */
}

/* WRONG: Do NOT use hardcoded values without documentation */
.widget-primary {
    background-color: #0f62fe;  /* ❌ Missing theme reference */
    color: #333;                /* ❌ Not a Carbon color */
}

critical_note.correct_pattern:

// In config.json:
"bindingType": {
  "name": "TimelineData",
  "isList": true,
  "type": "TimelineEvent"
}

// In inlineJavascript.js:
// CORRECT: Access the array through .items property
var timelineData = this.getData().items;

// WRONG: These will NOT work
var timelineData = this.getData();           // Returns object, not array
var timelineData = this.getData().events;    // Property 'events' doesn't exist
var timelineData = this.getData().timeline;  // Property 'timeline' doesn't exist
